import { Injectable } from '@angular/core';
import { Subject } from 'rxjs';
import { HttpRequest } from '@angular/common/http';

@Injectable({
  providedIn: 'root',
})
export class LoaderService {
  private isLoadingSubject = new Subject<boolean>();
  isLoading = this.isLoadingSubject.asObservable();
  private ignoredEndpoints = ['/bs-user/api/chat']; // Bỏ qua endpoint của chatbot

  constructor() {}

  show(req: HttpRequest<any>) {
    if (this.ignoredEndpoints.some(endpoint => req.url.includes(endpoint))) {
      return; // Không kích hoạt loading cho chatbot
    }
    this.isLoadingSubject.next(true);
  }

  hide(req: HttpRequest<any>) {
    if (this.ignoredEndpoints.some(endpoint => req.url.includes(endpoint))) {
      return; // Không thay đổi trạng thái loading
    }
    this.isLoadingSubject.next(false);
  }
}
